```class Solution {
public:
    int maxVowels(string s, int k) {
        int maxCount = 0, windowCount = 0;
        unordered_set<char> vowels = {'a', 'e', 'i', 'o', 'u'};
        for (int i = 0; i < s.length(); i++) {
            if (vowels.count(s[i])) windowCount++;
            if (i >= k && vowels.count(s[i - k])) windowCount--;
            if (i >= k - 1) maxCount = max(maxCount, windowCount);
        }
        return maxCount;
    }
};
